SELECT CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_1) THEN DATEFROMPARTS(YEAR(demo_retail.dbo.orders.order_date), MONTH(demo_retail.dbo.orders.order_date), 1) ELSE NULL END AS event_month, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_1 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) > :param_2) THEN :param_3 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_1 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < :param_4) THEN :param_5 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_1) THEN DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) ELSE NULL END AS lag_day, CASE WHEN (demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL) THEN DATEDIFF(day, demo_retail.dbo.orders.src_inserted_at, demo_retail.dbo.orders.loaded_at) ELSE NULL END AS delta_day, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_1) THEN :param_6 ELSE :param_7 END AS is_source_eligible, CASE WHEN (demo_retail.dbo.orders.order_date IS NULL) THEN :param_8 ELSE :param_9 END AS is_null_event_time, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NULL) THEN :param_10 ELSE :param_11 END AS is_null_source_only, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_12 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < :param_13) THEN :param_14 ELSE :param_15 END AS is_negative_clipped, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < :param_16) THEN :param_17 ELSE :param_18 END AS is_negative_lag_excluded, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= :param_1 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) > :param_19) THEN :param_20 ELSE :param_21 END AS is_overflow, CASE WHEN (demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL) THEN :param_22 ELSE :param_23 END AS is_delta_row  INTO #mp_dual 
FROM demo_retail.dbo.orders 
WHERE demo_retail.dbo.orders.loaded_at <= :as_of OR demo_retail.dbo.orders.loaded_at IS NULL
